import java.util.PriorityQueue;

public String smallestSubsequence(String s, int k, char letter, int repetition) {
    StringBuilder result = new StringBuilder();
    int letterCount = 0, n = s.length();
    for (char c : s.toCharArray()) if (c == letter) letterCount++;

    PriorityQueue<Character> pq = new PriorityQueue<>();
    for (int i = 0; i < n; i++) {
        if (s.charAt(i) <= letter || letterCount > repetition) {
            while (!pq.isEmpty() && pq.peek() > s.charAt(i)) {
                if (pq.poll() == letter) letterCount--;
            }
            pq.add(s.charAt(i));
            if (pq.size() > k) pq.poll();
        }
        if (k - pq.size() == repetition) letterCount--;
        repetition = Math.max(0, repetition);
    }

    while (!pq.isEmpty()) {
        result.append(pq.poll());
    }
    return result.toString();
}
```

